DROP TABLE IF EXISTS stats_moodle
CREATE TABLE stats_moodle ("NOME QUIZ" TEXT, "NOME CORSO" TEXT, "APERTURA" TEXT, Q INTEGER, "TIPO DI DOMANDA" TEXT, "NOME DOMANDA" TEXT, TENTATIVI INTEGER, "INDICE DI ABILITÀ" TEXT, "DEVIAZIONE STANDARD" TEXT, "INDICE DELLE RISPOSTE DATE A CASO" TEXT, "PESO PREVISTO" TEXT, "PESO EFFETTIVO" TEXT, "INDICE DI DISCRIMINAZIONE" TEXT, "EFFICIENZA DISCRIMINANTE" TEXT)